// Compute the week range: last Monday → Sunday
const now = new Date();
const dayOfWeek = now.getUTCDay();
const diffToMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
const monday = new Date(now);
monday.setUTCDate(now.getUTCDate() - diffToMonday - 7);
monday.setUTCHours(0, 0, 0, 0);
const sunday = new Date(monday);
sunday.setUTCDate(monday.getUTCDate() + 6);
sunday.setUTCHours(23, 59, 59, 999);

return [{
  json: {
    week_start: monday.toISOString().split('T')[0],
    week_end: sunday.toISOString().split('T')[0],
    week_start_iso: monday.toISOString(),
    week_end_iso: sunday.toISOString()
  }
}];

const metrics = $input.first().json;
const weekRange = $('Compute Week Range').first().json;
const userId = $('Get Active Users').item.json.user_id;

// Build scorecard data payload
const scorecardData = {
  deliveries_count: metrics.deliveries_count || 0,
  artifacts_updated: metrics.artifacts_updated || 0,
  feedback_count: metrics.feedback_count || 0,
  avg_rating: parseFloat(metrics.avg_rating) || 0,
  top_referenced_sections: metrics.top_referenced_sections || [],
  unaddressed_objections: metrics.unaddressed_items || [],
  coverage_gaps: metrics.coverage_gaps || [],
  actions_recommended: [],
  views_count: metrics.views_count || 0,
  unique_viewers: metrics.unique_viewers || 0
};

// Generate recommended actions
const actions = [];
if (scorecardData.avg_rating > 0 && scorecardData.avg_rating < 3.5) {
  actions.push('Content quality is below target. Review feedback to identify improvement areas.');
}
if ((scorecardData.coverage_gaps || []).filter(g => g && g.severity === 'high').length > 0) {
  actions.push('Address high-severity coverage gaps before next sales cycle.');
}
if (scorecardData.deliveries_count === 0) {
  actions.push('No artifacts delivered this week. Check if sales team needs updated content.');
}
if (scorecardData.views_count > 0 && scorecardData.feedback_count === 0) {
  actions.push('Artifacts viewed but no feedback collected. Prompt reps for ratings.');
}
if (scorecardData.unaddressed_objections.length > 0) {
  actions.push(`Top missing items: ${scorecardData.unaddressed_objections.slice(0, 3).join(', ')}. Consider adding these.`);
}
scorecardData.actions_recommended = actions;

return [{
  json: {
    user_id: userId,
    week_start: weekRange.week_start,
    week_end: weekRange.week_end,
    scorecard_data: JSON.stringify(scorecardData)
  }
}];
